using System;
using System.Collections.Generic;
using System.Xml;

public static class XmlConfigParser
{
    public static Dictionary<string,string> ParseConfiguration(string xmlContent)
    {
        var result = new Dictionary<string,string>();

        var settings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD
        };

        using (var reader = XmlReader.Create(new System.IO.StringReader(xmlContent), settings))
        {
            var doc = new XmlDocument
            {
                XmlResolver = new XmlUrlResolver()
            };
            doc.Load(reader);

            var nodeList = doc.SelectNodes("//Setting");
            if (nodeList != null)
            {
                foreach (XmlNode node in nodeList)
                {
                    if (node.Attributes != null)
                    {
                        var nameAttribute = node.Attributes["name"];
                        var valueAttribute = node.Attributes["value"];
                        if (nameAttribute != null && valueAttribute != null)
                        {
                            result[nameAttribute.Value] = valueAttribute.Value;
                        }
                    }
                }
            }
        }

        return result;
    }
}